#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_cpu_2.h"

//========================================================================================================================================================================================================200
//	KERNEL_CPU_2 FUNCTION
//========================================================================================================================================================================================================200

void 
kernel_cpu_2(	int cores_arg,

				knode *knodes,
				long knodes_elem,

				int order,
				long maxheight,
				int count,

				long *currKnode,
				long *offset,
				long *lastKnode,
				long *offset_2,
				int *start,
				int *end,
				int *recstart,
				int *reclength)
{
	//======================================================================================================================================================150
	//	Variables
	//======================================================================================================================================================150

	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	// threads per block equivalent
	int threadsPerBlock;
	threadsPerBlock = 1024 > order ? order : 1024;

	// blocks per grid equivalent
	int blocksPerGrid;
	blocksPerGrid = count;

	printf("# of blocks = %d, # of threads/block = %d\n", blocksPerGrid, threadsPerBlock);

	time1 = get_time();
	time2 = get_time();
	time3 = get_time();
	time4 = get_time();

	//======================================================================================================================================================150
	//	KERNEL (OpenMP parallel)
	//======================================================================================================================================================150

	omp_set_num_threads(cores_arg);

	#pragma omp parallel for schedule(static)
	for (int bid = 0; bid < count; bid++) {

		// process levels of the tree
		for (int i = 0; i < maxheight; i++) {

			for (int thid = 0; thid < threadsPerBlock; thid++) {
				if ((start[bid] >= knodes[currKnode[bid]].keys[thid]) &&
				    (start[bid] < knodes[currKnode[bid]].keys[thid+1])) {
					if (knodes_elem > knodes[currKnode[bid]].indices[thid]) {
						offset[bid] = knodes[currKnode[bid]].indices[thid];
					}
				}
				if ((end[bid] >= knodes[lastKnode[bid]].keys[thid]) &&
				    (end[bid] < knodes[lastKnode[bid]].keys[thid+1])) {
					if (knodes_elem > knodes[lastKnode[bid]].indices[thid]) {
						offset_2[bid] = knodes[lastKnode[bid]].indices[thid];
					}
				}
			}

			// set for next tree level (thread 0 action)
			currKnode[bid] = offset[bid];
			lastKnode[bid] = offset_2[bid];
		}

		// process leaves
		// Find the index of the starting record
		for (int thid = 0; thid < threadsPerBlock; thid++) {
			if (start[bid] == knodes[currKnode[bid]].keys[thid]) {
				recstart[bid] = knodes[currKnode[bid]].indices[thid];
			}
		}

		// Find the index of the ending record
		for (int thid = 0; thid < threadsPerBlock; thid++) {
			if (end[bid] == knodes[lastKnode[bid]].keys[thid]) {
				reclength[bid] = knodes[lastKnode[bid]].indices[thid] - recstart[bid] + 1;
			}
		}
	}

	time5 = get_time();
	time6 = get_time();

	//======================================================================================================================================================150
	//	DISPLAY TIMING
	//======================================================================================================================================================150

	printf("Time spent in different stages of CPU KERNEL:\n");

	printf("%15.12f s, %15.12f % : CPU: SET DEVICE / DRIVER INIT\n",	(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: ALLOCATE CPU MEMORY\n", 		(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: COPY DATA TO CPU\n", 			(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: PROCESSING\n", 				(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: KERNEL\n", 					(float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: COPY DATA FROM CPU\n", 		(float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time6-time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", 												(float) (time6-time0) / 1000000);
}
